module top_module(
    input [7:0] DATA,
    input [2:0] SHIFT_AMOUNT,
    input SHIFT_DIRECTION,
    output [7:0] SHIFTED_DATA
);reg [7:0] shifted_data;

    always @(*) begin
        if (SHIFT_DIRECTION == 0) begin
            shifted_data = DATA << SHIFT_AMOUNT;
        end else begin
            shifted_data = DATA >> SHIFT_AMOUNT;
        end
    end

    wire __SHIFTED_DATA_tmp = shifted_data;
    assign SHIFTED_DATA = __SHIFTED_DATA_tmp;

endmodule
